-- View: dw.v_routes_consistently_late
-- Extracted from Redshift Serverless workgroup: team, database: dev
-- Extracted: 2026-04-03

CREATE OR REPLACE VIEW dw.v_routes_consistently_late AS
SELECT daily_otp.agencykey, daily_otp.agencyname, daily_otp."mode", daily_otp.routekey, daily_otp.routeid, daily_otp.routeshortname, daily_otp.routelongname, count(*) AS days_evaluated, sum(CASE WHEN (daily_otp.day_otp_pct < (70)::numeric) THEN 1 ELSE 0 END) AS days_below_70pct, round(avg(daily_otp.day_otp_pct), 1) AS avg_otp_pct, min(daily_otp.day_otp_pct) AS worst_day_otp_pct, "max"(daily_otp.day_otp_pct) AS best_day_otp_pct FROM (SELECT fs.agencykey, a.agencyname, a."mode", fs.routekey, dr.routeid, dr.routeshortname, dr.routelongname, dd.fulldate, count(*) AS total_stops, sum(CASE WHEN (fs.isontime = true) THEN 1 ELSE 0 END) AS ontime_stops, round(((100.0 * ((sum(CASE WHEN (fs.isontime = true) THEN 1 ELSE 0 END))::numeric)::numeric(18,0)) / ((CASE WHEN (count(*) = 0) THEN NULL::bigint ELSE count(*) END)::numeric)::numeric(18,0)), 1) AS day_otp_pct FROM (((dw.factstop fs JOIN dw.dimroute dr ON ((dr.routekey = fs.routekey))) JOIN dw.dimagency a ON ((a.agencykey = fs.agencykey))) JOIN dw.dimdate dd ON ((dd.datekey = fs.datekey))) WHERE ((fs.isofficial = true) AND (dd.fulldate >= (('now'::text)::date - '30 days'::interval))) GROUP BY fs.agencykey, a.agencyname, a."mode", fs.routekey, dr.routeid, dr.routeshortname, dr.routelongname, dd.fulldate) daily_otp GROUP BY daily_otp.agencykey, daily_otp.agencyname, daily_otp."mode", daily_otp.routekey, daily_otp.routeid, daily_otp.routeshortname, daily_otp.routelongname HAVING (sum(CASE WHEN (daily_otp.day_otp_pct < (70)::numeric) THEN 1 ELSE 0 END) >= 5) ORDER BY sum(CASE WHEN (daily_otp.day_otp_pct < (70)::numeric) THEN 1 ELSE 0 END) DESC, round(avg(daily_otp.day_otp_pct), 1);;
